const calc = require('../src/precision-calc');

describe('Precision Calculations', () => {
  test('should calculate tax with precision', () => {
    const result = calc.calculateTax(1234.56, 0.10);
    expect(result).toBeCloseTo(123.46, 2);  // 2 decimal places
  });

  test('should compute interest rate accurately', () => {
    const result = calc.computeRate(1000, 1051.27, 1);
    expect(result).toBeCloseTo(0.0500, 4);  // 4 decimal places
  });

  test('should round currency correctly', () => {
    const result = calc.roundCurrency(99.9891234);
    expect(result).toBeCloseTo(99.99, 2);  // 2 decimal places
  });

  test('should format percentage', () => {
    expect(calc.formatPercent(0.125)).toBe('12.5%');
  });
});

function calculateTax(amount, taxRate) {
  // Bug: not rounding result
  return amount * taxRate;
}

function computeRate(principal, finalAmount, years) {
  // Bug: accumulating floating point errors
  const rate = (finalAmount / principal - 1) / years;
  return rate;
}

function roundCurrency(value) {
  // Bug: using Math.floor instead of proper rounding
  return Math.floor(value * 100) / 100;
}

function formatPercent(decimal) {
  return (decimal * 100) + '%';
}

module.exports = {
  calculateTax,
  computeRate,
  roundCurrency,
  formatPercent
};

